// @ts-nocheck
"use client";

import { useRef, useMemo, Suspense } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import { Float, Edges, useTexture } from "@react-three/drei";
import * as THREE from "three";

function DataAvatar() {
  const groupRef = useRef();
  const innerRef = useRef();
  const ringRef = useRef();
  
  // Load the Anime Avatar Image perfectly as a 3D Texture
  const texture = useTexture("/rohith_anime_avatar.png");
  
  const { mouse, viewport } = useThree();

  useFrame((state, delta) => {
    // The avatar core tracks the mouse smoothly
    if (groupRef.current) {
      // Keep it anchored dynamically on the right side of the screen
      const responsivenessOffsetX = viewport.width > 8 ? 3 : 0;
      const targetX = responsivenessOffsetX + (mouse.x * 0.5);
      const targetY = (mouse.y * 0.5);
      
      groupRef.current.position.x += (targetX - groupRef.current.position.x) * 0.05;
      groupRef.current.position.y += (targetY - groupRef.current.position.y) * 0.05;
      
      // Look at cursor
      groupRef.current.rotation.y = THREE.MathUtils.lerp(groupRef.current.rotation.y, mouse.x * Math.PI * 0.1, 0.05);
      groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, -mouse.y * Math.PI * 0.1, 0.05);
    }

    if (innerRef.current) {
      innerRef.current.rotation.z += delta * 0.1;
    }
    
    if (ringRef.current) {
      ringRef.current.rotation.x += delta * 0.2;
      ringRef.current.rotation.y += delta * 0.1;
    }
  });

  return (
    <group ref={groupRef} position={[3, 0, 0]}>
      <Float speed={1.5} rotationIntensity={0.1} floatIntensity={1}>
        <group>
          {/* Main Server/Core Monolith Avatar Panel */}
          <mesh castShadow>
             <planeGeometry args={[4.5, 4.5]} />
             <meshStandardMaterial 
                map={texture} 
                transparent 
                opacity={0.9} 
                emissive={new THREE.Color("#222")} 
             />
             <Edges color="#ffffff" threshold={15} opacity={0.3} transparent scale={1.01} />
          </mesh>
          
          {/* Glass backing panel for 3D depth */}
          <mesh position={[0, 0, -0.2]}>
            <boxGeometry args={[4.8, 4.8, 0.1]} />
            <meshStandardMaterial color="#000" metalness={0.8} roughness={0.2} transparent opacity={0.8} />
            <Edges color="#ffffff" opacity={0.1} transparent />
          </mesh>

          {/* Orbiting Database Sharding Rings */}
          <group ref={ringRef}>
            {[...Array(3)].map((_, i) => (
              <mesh key={i} rotation={[Math.PI / (i + 1.2), 0, Math.PI / i]}>
                <torusGeometry args={[3.8 + i * 0.5, 0.003, 16, 120]} />
                <meshBasicMaterial color="#ffffff" transparent opacity={0.3} side={THREE.DoubleSide} />
              </mesh>
            ))}
            {/* Fragments of Data passing around */}
            {[...Array(15)].map((_, i) => {
              const angle = (i / 15) * Math.PI * 2;
              return (
                <mesh key={i} position={[Math.cos(angle) * 4, Math.sin(angle) * 4, Math.sin(angle * 3) * 1.5]}>
                  <boxGeometry args={[0.08, 0.08, 0.08]} />
                  <meshBasicMaterial color="#ffffff" opacity={0.5} transparent />
                </mesh>
              );
            })}
          </group>
        </group>
      </Float>
    </group>
  );
}

function DataGrid() {
  const pointsRef = useRef();
  
  // Create a structured massive grid mimicking infinite storage arrays
  const particles = useMemo(() => {
    const geo = new THREE.BufferGeometry();
    const count = 3000;
    const positions = new Float32Array(count * 3);
    
    for (let i = 0; i < count; i++) {
      positions[i * 3] = (Math.random() - 0.5) * 50;
      positions[i * 3 + 1] = (Math.random() - 0.5) * 50;
      positions[i * 3 + 2] = (Math.random() - 0.5) * 50;
    }
    geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    return geo;
  }, []);

  useFrame((_, delta) => {
    if (pointsRef.current) {
      pointsRef.current.rotation.y += delta * 0.01;
    }
  });

  return (
    <points ref={pointsRef} geometry={particles}>
      <pointsMaterial 
        size={0.03}
        color="#ffffff"
        transparent
        opacity={0.3}
        sizeAttenuation
      />
    </points>
  );
}

export default function HeroCanvas() {
  return (
    <div className="w-full h-full">
      <Canvas camera={{ position: [0, 0, 8], fov: 50 }} gl={{ antialias: true, alpha: true }} dpr={[1, 1.5]}>
        <ambientLight intensity={0.8} />
        <directionalLight position={[10, 10, 5]} intensity={1.5} />
        <directionalLight position={[-10, -10, -5]} intensity={0.5} color="#ffffff" />
        
        <DataGrid />
        <Suspense fallback={null}>
          <DataAvatar />
        </Suspense>
      </Canvas>
    </div>
  );
}
